package in.StringHanding;

public class TypesOfStringObjects {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		String s1="Chandini";//String Literals|scp
		String s2=new String("Java");//String with new keyword | heap ,one in string constant pool,heap so it creates 2 obj
		String s3="Ratna";//0 object-with out new keyword it has 0 objects
		String s4="java";//0 object
		System.out.println(s1);
		System.out.println(s2);
		System.out.println(s3);
		System.out.println(s4);


	}

}
